class Solution(object):
    def maximumLength(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        n = len(nums)
        # Remap values to [0, num_unique-1]
        unique_vals = sorted(set(nums))
        val_map = {v: i for i, v in enumerate(unique_vals)}

        # dp[changes][val] = max length with at most 'changes' changes, ending with 'val'
        from collections import defaultdict
        dp = [defaultdict(int) for _ in range(k + 1)]

        result = 1

        for num in nums:
            mapped_val = val_map[num]
            # Process in reverse to avoid using updated values
            new_dp = [d.copy() for d in dp]

            for changes in range(k, -1, -1):
                # Option 1: Start new sequence at this element
                new_dp[changes][mapped_val] = max(new_dp[changes][mapped_val], 1)

                # Option 2: Extend from different value (use one change)
                if changes > 0:
                    for prev_val in dp[changes - 1]:
                        if prev_val != mapped_val:
                            new_dp[changes][mapped_val] = max(
                                new_dp[changes][mapped_val],
                                dp[changes - 1][prev_val] + 1
                            )

                # Option 3: Extend from same value (no change)
                if changes <= k:
                    new_dp[changes][mapped_val] = max(
                        new_dp[changes][mapped_val],
                        dp[changes][mapped_val] + 1
                    )

            dp = new_dp
            for changes in range(k + 1):
                for length in dp[changes].values():
                    result = max(result, length)

        return result
